SELECT COUNT(*) AS total_results
FROM class_results
WHERE rider_id = 1;

SELECT profile_photo_url
FROM rider_profiles
WHERE IFNULL(rider_achievements, '') != '';

SELECT class_id, COUNT(comment_id) AS total_comments
FROM class_comments
GROUP BY class_id;

SELECT DISTINCT r.rider_name
FROM riders r
JOIN class_results cr ON r.rider_id = cr.rider_id;

SELECT AVG(cr.entries) AS average_entries_per_class
FROM class_results cr
JOIN classes c ON cr.class_id = c.class_id;

SELECT COUNT(comment_id) AS approved_comments_count
FROM class_comments
WHERE class_id = 1 AND comment_status = 'approved';
